async function runCodexFix(issueId) { if (!state.project || state.codexFixId) return; const issue = allIssues().find(item => item.id === issueId); if (!issue) return; state.codexFixId = issueId; state.codexLog = ['Preparing Codex…\n']; state.codexResult = null; state.scanning = true; state.loadingLabel = 'Codex is applying the requested fix…'; renderProject(); try { await window.api.fixViaCodex(state.project.id, issueId); state.loadingLabel = 'Re-scanning the project…'; recordCodexResult(await window.api.runScan(state.project.id), [issue], 'finding'); } catch (error) { window.alert(error.message || 'Codex could not complete this fix.'); } finally { state.codexFixId = null; state.scanning = false; renderProject(); } }
